function assignSnapshot(data){if(!data?.game)return;if(backend.gameId&&data.game.id!==backend.gameId&&backend.token)return;state.game=normalizeGame(data.game);state.participants=Array.isArray(data.participants)?data.participants.map(normalizeParticipant):state.participants;if(Array.isArray(data.sos))state.sos=data.sos.map(normalizeAlert);if(Array.isArray(data.messages))state.messages=data.messages;if(Array.isArray(data.contacts))state.contacts=data.contacts;if(Array.isArray(data.staff)){state.staff=data.staff;ui.staffAccounts=data.staff;ui.staffAccountsLoaded=true;}if(Array.isArray(data.staffPresets)){ui.staffPresets=data.staffPresets;ui.staffPresetsLoaded=true;}if(data.currentStaff)state.currentStaff=data.currentStaff;if(Array.isArray(data.events))state.events=data.events.map(mapServerEvent);if(Array.isArray(data.archives)){ui.archives=data.archives;ui.archivesLoaded=true;}}
