function updateConnectionDom(){const node=$('.connection');if(node)node.outerHTML=connection();}
function applySnapshot(data){
  const before=stateUiSignature();
  const previousState=state.game.state,previousGameId=state.game.id;
  assignSnapshot(data);
  if(previousGameId===state.game.id&&previousState!=='ACTIVE'&&state.game.state==='ACTIVE')resetGameMapViews(state.game.id);
  save(false);
  if(ui.view==='admin'&&ui.adminTab==='settings'){updateActiveMaps();updateLiveLocationDom();checkCritical();return;}
  if(before===stateUiSignature()){updateActiveMaps();updateLiveLocationDom();return;}
  scheduleRender();checkCritical();
}
function connectRealtime(token,gameId){
  if(!backend.available||!window.io||!token)return;
  backend.token=token;backend.gameId=gameId||backend.gameId||state.game.id;
  backend.socket?.disconnect();
  const socket=window.io({auth:{token,gameId:backend.gameId}});backend.socket=socket;
  socket.on('connect',()=>{backend.connected=true;updateConnectionDom();});
  socket.on('disconnect',()=>{backend.connected=false;updateConnectionDom();});
  socket.on('connect_error',error=>{backend.connected=false;if(String(error?.message).includes('unauthorized'))handleUnauthorized();else if(Date.now()-gpsErrorShownAt>15000){gpsErrorShownAt=Date.now();toast('Brak połączenia realtime','Aplikacja spróbuje połączyć się ponownie.','warning');}});
  socket.on('session:revoked',()=>handleUnauthorized());
  socket.on('state:snapshot',applySnapshot);
  socket.on('game:changed',game=>{const was=state.game.state;state.game=normalizeGame(game);if(was!=='ACTIVE'&&state.game.state==='ACTIVE')resetGameMapViews(state.game.id);save(false);scheduleRender();});
  socket.on('event:new',raw=>{const item=mapServerEvent(raw);state.events=state.events.filter(event=>event.id!==item.id);state.events.unshift(item);state.events=state.events.slice(0,500);if(ui.view==='admin'&&['events','dashboard'].includes(ui.adminTab))scheduleRender();});
  socket.on('sos:changed',raw=>{const alert=normalizeAlert(raw),i=state.sos.findIndex(s=>s.id===alert.id);if(i>=0)state.sos[i]=alert;else state.sos.unshift(alert);save(false);scheduleRender();checkCritical();});
  socket.on('message:new',message=>{state.messages=state.messages.filter(item=>item.id!==message.id);state.messages.unshift(message);save(false);toast(message.signalType?'Sygnał sędziego':'Nowy komunikat',message.body,message.signalType?'critical':'');if(message.signalType)alarmSequence();else beep(720,.12);if(enabled('messageNotifications'))showFieldNotification(message.signalType?`SYGNAŁ ${message.signalType}`:`Wiadomość · ${message.senderName||'Dowodzenie'}`,message.body);if((ui.view==='player'&&ui.playerTab==='messages')||(ui.view==='staff'&&ui.staffTab==='messages'))scheduleRender();});
}
