        const fov=enabled('fovPrediction')&&fovPoints(p);if(fov)window.L.polygon(fov,{color:teamColor,weight:1,fillColor:teamColor,fillOpacity:.12,interactive:false}).addTo(fovLayer);
        const tooltip=`<b>${esc(p.callsign)}</b><br>${p.team}${squad?` · ${esc(squad.name)}`:''} · ${esc(roleByCode(p.role).name)}<br>${statusLabel(p.status)} · ${p.healthState||'HEALTHY'}${enabled('showAccuracy')?` · ±${Math.round(p.accuracy||0)} m`:''}${Number.isFinite(Number(p.heading))?`<br>FOV szacowany: ${Math.round(p.heading)}° (${esc(p.headingSource||'GPS')})`:''}<br>${mgrs(p.lat,p.lon)}`;
