function playerInfoHtml(me){const role=roleByCode(me.role),squad=teamById(me.squadId);return `<section class="player-info-stack"><article class="mission-card player-id-card"><span class="eyebrow">ID OPERATORA</span><strong>${esc(me.id)}</strong><button class="btn btn-blue" data-action="copy-player-id">Kopiuj ID</button></article>${roleAbilityHtml(me)}<article class="mission-card telemetry-card"><div><span class="label">TRAFIENIA</span><strong>${me.hitCount||0}/${state.game.modeSettings?.hitsToRespawn||1}</strong></div><div><span class="label">RESPAWNY</span><strong>${me.respawnCount||0}</strong></div><div><span class="label">KIERUNEK</span><strong data-live-heading>${Number.isFinite(Number(me.heading))?`${Math.round(me.heading)}°`:'—'}</strong></div><div><span class="label">GPS</span><strong>${me.accuracy?`±${Math.round(me.accuracy)} m`:'—'}</strong></div></article><article class="mission-card info-summary"><h3>Dane przydziału</h3><p><b>Sesja:</b> ${esc(state.game.code)} · ${esc(state.game.name)}</p><p><b>Strona:</b> ${me.team}</p><p><b>Drużyna:</b> ${squad?esc(squad.name):'brak / neutralny'}</p><p><b>Rola:</b> ${esc(role.name)}</p><p><b>Mapa:</b> ${me.mapAccess===false?'wyłączona przez GM':'dostępna'}</p><p><b>Widoczność GPS:</b> ${me.team==='NEUTRAL'?(me.fieldVisible?'widoczny':'ukryty'):'zgodna z zasadami drużyny'}</p></article></section>`;}
