  $$('[data-objective-status]').forEach(input=>input.onchange=()=>updateObjectiveStatus(input.dataset.objectiveStatus,input.value));
  $('#event-filter')?.addEventListener('change',event=>{ui.eventFilter=event.target.value;render();});
  $('#event-search')?.addEventListener('input',event=>{ui.eventSearch=event.target.value;const filtered=state.events.filter(item=>(ui.eventFilter==='ALL'||item.type.includes(ui.eventFilter))&&(!ui.eventSearch||`${item.type} ${item.text}`.toLocaleLowerCase('pl-PL').includes(ui.eventSearch.toLocaleLowerCase('pl-PL'))));const timeline=$('.event-history');if(timeline)timeline.innerHTML=eventsHtml(filtered);});
  $('#participant-search')?.addEventListener('input',event=>{ui.participantSearch=event.target.value;const position=event.target.selectionStart;render();requestAnimationFrame(()=>{const input=$('#participant-search');input?.focus();input?.setSelectionRange(position,position);});});
