    if(backend.available){const message=await api('/api/messages',{method:'POST',body:JSON.stringify({gameId:activeGameId(),body,audience:audience==='WSZYSCY'?'ALL':audience})});state.messages=state.messages.filter(item=>item.id!==message.id);state.messages.unshift(message);}
