async function sendCommanderMessage(e){e.preventDefault();const me=currentPlayer(),body=$('#commander-message-body')?.value.trim();if(!me||!body)return;try{await api('/api/messages',{method:'POST',body:JSON.stringify({audience:me.team,body})});toast('Rozkaz nadany',`Cała strona ${me.team} otrzymała komunikat.`);render();}catch(error){toast('Nie wysłano rozkazu',error.message,'critical');}}
async function assistParticipant(id){try{const result=await api(`/api/participants/${id}/assist`,{method:'POST',body:'{}'}),target=normalizeParticipant(result.participant),index=state.participants.findIndex(player=>player.id===id);if(index>=0)state.participants[index]=target;toast('Pomoc zakończona',`${target.callsign} wraca do rozgrywki.`);render();}catch(error){toast('Pomoc niedostępna',error.message,'warning');}}
async function fieldControl(command,signal){try{const result=await api('/api/participants/field-control',{method:'POST',body:JSON.stringify({action:command,signal:signal||undefined})});if(result.game)state.game=normalizeGame(result.game);if(result.participant){const participant=normalizeParticipant(result.participant),index=state.participants.findIndex(item=>item.id===participant.id);if(index>=0)state.participants[index]=participant;}const labels={PAUSE:'Rozgrywka wstrzymana',RESUME:'Rozgrywka wznowiona',SIGNAL:'Sygnał nadany',VISIBILITY:result.participant?.fieldVisible?'Twój GPS jest widoczny':'Twój GPS jest ukryty'};toast(labels[command]||'Polecenie wykonane');render();}catch(error){toast('Polecenie niedostępne',error.message,'warning');}}
function handleAction(action,button){
  if(action==='join-next') nextJoin();
  if(action==='join-back'){ui.joinStep=Math.max(1,ui.joinStep-1);render();}
  if(action==='test-sound'){unlockAudio();beep(660,.18,.16);setTimeout(()=>beep(920,.22,.2),240);setTimeout(()=>beep(1180,.32,.24),520);toast('Test dźwięku','Odtworzono głośny sygnał końcowy.');}
  if(action==='test-gps') requestGpsTest();
  if(action==='timer-start') startTimer();
  if(action==='sos-open') showSosModal();
  if(action==='simulate') simulateMovement();
  if(action==='export-csv') exportCsv();
  if(action==='boundary-current'){ui.boundaryDraft=(state.game.boundary||polygon).map(point=>[...point]);updateBoundaryEditor();}
  if(action==='boundary-clear'){ui.boundaryDraft=[];updateBoundaryEditor();toast('Punkty wyczyszczone','Widok mapy pozostał w tej samej pozycji.');}
  if(action==='boundary-around-me') boundaryAroundMe();
  if(action==='boundary-around-center') boundaryAroundCenter();
  if(action==='boundary-save') saveBoundary();
  if(action==='participant-save') saveParticipant(button.dataset.id);
  if(action==='participant-respawn') patchParticipant(button.dataset.id,{status:'RESPAWN_WAIT',respawnRequired:true},'Respawn został wymuszony.');
  if(action==='participant-clear') patchParticipant(button.dataset.id,{hitCount:0,respawnRequired:false},'Trafienia i wymóg respawnu wyczyszczone.');
  if(action==='team-save')saveTeam(button.dataset.id);
  if(action==='team-delete')deleteOperationalTeam(button.dataset.id);
  if(action==='role-save')saveRole(button.dataset.id);
  if(action==='role-delete')deleteOperationalRole(button.dataset.id);
  if(action==='role-assist')assistParticipant(button.dataset.id);
  if(action==='field-control')fieldControl(button.dataset.command,button.dataset.signal);
  if(action==='player-messages'){ui.playerTab='messages';render();}
  if(action==='copy-player-id'){navigator.clipboard?.writeText(currentPlayer()?.id||'');toast('ID skopiowane');}
  if(action==='zone-new')newZoneDraft();
  if(action==='zone-add-required')newZoneDraft(button.dataset.zoneType||'RESPAWN');
  if(action==='zone-select'){ui.selectedZoneId=button.dataset.id;render();}
  if(action==='zone-remove')removeZoneDraft(button.dataset.id);
  if(action==='zone-clear-points')clearZonePoints();
  if(action==='zone-square')squareZoneDraft();
  if(action==='zones-save')saveZoneDrafts();
  if(action==='objective-delete')deleteObjective(button.dataset.id);
  if(action==='staff-save')saveStaffAccount(button.dataset.id);
  if(action==='staff-revoke'&&confirm('Wylogować to konto ze wszystkich urządzeń?'))saveStaffAccount(button.dataset.id,{revokeSessions:true});
  if(action==='staff-delete')deleteStaffAccount(button.dataset.id);
  if(action==='staff-preset-apply')applyPermissionPreset(button.dataset.id);
  if(action==='staff-preset-delete'&&confirm('Usunąć ten własny preset?'))deleteStaffPreset(button.dataset.id);
  if(action==='staff-refresh')loadStaffAccounts().then(render);
  if(action==='score-change')changeScore(button.dataset.team,Number(button.dataset.delta));
  if(action==='hit-report')reportHit();
  if(action==='install')installApp();
  if(action==='field-mode')toggleFieldMode();
  if(action==='compass-enable')enableCompass(true);
  if(action==='zone-interact')interactWithZone(button.dataset.id);
  if(action==='replay-load')loadReplay();
  if(action==='replay-play')toggleReplay();
  if(action==='replay-delete')confirmReplayDelete();
  if(action==='archive-create')createSessionArchive();
  if(action==='archive-download')downloadSessionArchive(button.dataset.id);
  if(action==='archive-delete')deleteSessionArchive(button.dataset.id);
  if(action==='preset-apply')applySessionPreset(button.dataset.id);
  if(action==='notifications-enable')enableNotifications();
  if(action==='features-recommended'){const recommended=new Set(MODE_RECOMMENDED_FEATURES[ui.selectedMode||state.game.mode]||[]);$$('[data-feature]').forEach(input=>{if(recommended.has(input.dataset.feature))input.checked=true;});toast('Zalecane funkcje zaznaczone','Kliknij „Zapisz funkcje”, aby je zastosować.');}
  if(action==='focus-sos'){const me=currentPlayer();if(me?.mapAccess===false)return toast('Mapa jest wyłączona','Administrator wyłączył dostęp do mapy dla Twojego konta.','warning');ui.playerTab='map';render();}
}
